  "inlineSchema": "// QuickSend Database Schema\n// Run: npx prisma migrate dev --name init\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─── User ─────────────────────────────────────────────────────────────────────\n\nmodel User {\n  id           String   @id @default(uuid())\n  email        String   @unique\n  phone        String?  @unique\n  firstName    String\n  lastName     String\n  passwordHash String\n  role         UserRole @default(USER)\n\n  // ILP wallet info\n  walletAddress String? @unique // their Open Payments wallet URL (external wallet)\n  ilpAccountId  String? @unique // internal Rafiki account ID (if hosted on your Rafiki)\n\n  // App state\n  isVerified    Boolean   @default(false)\n  isActive      Boolean   @default(true)\n  kycStatus     KYCStatus @default(PENDING)\n  kycVerifiedAt DateTime?\n\n  // Balance mirror (kept in sync with Rafiki via webhooks)\n  // Stored in the smallest asset unit (cents for USD, i.e. scale=2)\n  balanceCents BigInt @default(0)\n  assetCode    String @default(\"USD\")\n  assetScale   Int    @default(2)\n\n  // Relations\n  outgoingPayments Payment[]      @relation(\"SenderPayments\")\n  incomingPayments Payment[]      @relation(\"ReceiverPayments\")\n  contacts         Contact[]\n  refreshTokens    RefreshToken[]\n  auditLogs        AuditLog[]\n  notifications    Notification[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([email])\n  @@index([walletAddress])\n}\n\nenum UserRole {\n  USER\n  ADMIN\n  SUPPORT\n}\n\nenum KYCStatus {\n  PENDING\n  SUBMITTED\n  APPROVED\n  REJECTED\n}\n\n// ─── Contact ──────────────────────────────────────────────────────────────────\n\nmodel Contact {\n  id     String @id @default(uuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  name          String\n  initials      String\n  color         String  @default(\"#D1FAE5\")\n  walletAddress String // Open Payments URL of the contact\n  phone         String?\n  email         String?\n  notes         String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([userId, walletAddress])\n  @@index([userId])\n}\n\n// ─── Payment ──────────────────────────────────────────────────────────────────\n\nmodel Payment {\n  id String @id @default(uuid())\n\n  // Parties\n  senderId   String\n  sender     User    @relation(\"SenderPayments\", fields: [senderId], references: [id])\n  receiverId String?\n  receiver   User?   @relation(\"ReceiverPayments\", fields: [receiverId], references: [id])\n\n  // Recipient info (for external wallets where receiverId is null)\n  recipientWalletAddress String\n  recipientName          String\n\n  // Amounts (in smallest unit, e.g. cents)\n  debitAmountCents   BigInt\n  receiveAmountCents BigInt\n  feeAmountCents     BigInt @default(0)\n  assetCode          String @default(\"USD\")\n  assetScale         Int    @default(2)\n\n  // ILP references\n  ilpQuoteId           String? @unique\n  ilpOutgoingPaymentId String? @unique\n  ilpIncomingPaymentId String?\n\n  // State machine\n  status     PaymentStatus @default(PENDING)\n  failReason String?\n\n  // Metadata\n  note      String?\n  reference String? @unique @default(cuid())\n\n  // Timestamps\n  initiatedAt DateTime  @default(now())\n  processedAt DateTime?\n  completedAt DateTime?\n  failedAt    DateTime?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([senderId])\n  @@index([receiverId])\n  @@index([status])\n  @@index([ilpOutgoingPaymentId])\n  @@index([createdAt])\n}\n\nenum PaymentStatus {\n  PENDING // Created, not yet submitted to ILP\n  QUOTING // Fetching ILP quote\n  QUOTED // Quote obtained, awaiting user confirmation\n  PROCESSING // Submitted to ILP, awaiting completion\n  COMPLETED // ILP payment completed\n  FAILED // ILP payment failed\n  CANCELLED // Cancelled by user before processing\n  REVERSED // Successfully reversed/refunded\n}\n\n// ─── Refresh Tokens ───────────────────────────────────────────────────────────\n\nmodel RefreshToken {\n  id        String    @id @default(uuid())\n  userId    String\n  user      User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  token     String    @unique\n  expiresAt DateTime\n  revokedAt DateTime?\n  userAgent String?\n  ipAddress String?\n\n  createdAt DateTime @default(now())\n\n  @@index([userId])\n  @@index([token])\n}\n\n// ─── Audit Log ────────────────────────────────────────────────────────────────\n\nmodel AuditLog {\n  id         String  @id @default(uuid())\n  userId     String?\n  user       User?   @relation(fields: [userId], references: [id])\n  action     String\n  resource   String\n  resourceId String?\n  metadata   Json?\n  ipAddress  String?\n  userAgent  String?\n\n  createdAt DateTime @default(now())\n\n  @@index([userId])\n  @@index([action])\n  @@index([createdAt])\n}\n\n// ─── Notifications ────────────────────────────────────────────────────────────\n\nmodel Notification {\n  id     String           @id @default(uuid())\n  userId String\n  user   User             @relation(fields: [userId], references: [id], onDelete: Cascade)\n  type   NotificationType\n  title  String\n  body   String\n  data   Json?\n  isRead Boolean          @default(false)\n  readAt DateTime?\n\n  createdAt DateTime @default(now())\n\n  @@index([userId, isRead])\n}\n\nenum NotificationType {\n  PAYMENT_SENT\n  PAYMENT_RECEIVED\n  PAYMENT_FAILED\n  ACCOUNT_VERIFIED\n  SECURITY_ALERT\n  SYSTEM\n}\n\n// ─── ILP Webhook Events ───────────────────────────────────────────────────────\n\nmodel WebhookEvent {\n  id          String             @id @default(uuid())\n  eventType   String\n  payload     Json\n  status      WebhookEventStatus @default(PENDING)\n  processedAt DateTime?\n  error       String?\n  retries     Int                @default(0)\n\n  createdAt DateTime @default(now())\n\n  @@index([eventType])\n  @@index([status])\n}\n\nenum WebhookEventStatus {\n  PENDING\n  PROCESSED\n  FAILED\n  IGNORED\n}\n",
